/*\n\ncommit b88c5481f5f8a2dd2de0f823f536071f676bcbc7\nAuthor: Zhaoyang Huang <zhaoyang.huang@unisoc.com>\nDate:   Thu Feb 12 11:21:11 2026 +0800\n\n    mm: remove '!root_reclaim' checking in should_abort_scan()\n    \n    Nowadays, ANDROID system replaces madvise with memory.reclaim to\n    implement user space memory management which desires to reclaim a\n    certain amount of memcg's memory.  However, oversized reclaiming and\n    high latency are observed [1] as there is no limitation over\n    nr_reclaimed inside try_to_shrink_lruvec when MGLRU enabled.  Besides,\n    this could also affect all none root_reclaim such as reclaim_high etc.\n    \n    For try_to_free_mem_cgroup_pages -> shrink_node_memcgs -> shrink_lruvec\n    -> lru_gen_shrink_lruvec -> try_to_shrink_lruvec, the !root_reclaim(sc)\n    check was there for reclaim fairness, which was necessary before commit\n    b82b530740b9 (\"mm: vmscan: restore incremental cgroup iteration\")\n    because the fairness depended on attempted proportional reclaim from\n    every memcg under the target memcg.\n    \n    However after commit b82b530740b9 there is no longer a need to visit\n    every memcg to ensure fairness, horray.  The problem is for large\n    lruvecs, the lack of a check against sc->nr_to_reclaim inside\n    try_to_shrink_lruvec (caused by the continued presence of the\n    !root_reclaim(sc) check) can cause overreclaim.  The non-MGLRU\n    implementation in shrink_lruvec already checks nr_reclaimed against\n    nr_to_reclaim.\n    \n    [1]\n    test log which shows a nr_to_reclaim=32 pages proactive reclaim ended with\n    nr_reclaimed=394.\n    \n    [  485.100981] memcg iter ffffff8086535a00 nr_to_reclaim 32 nr_reclaimed 0\n    [  485.106927] memcg iter ffffff8086535a00 nr_to_reclaim 32 nr_reclaimed 127\n    [  485.109652] memcg iter ffffff80744e1400 nr_to_reclaim 32 nr_reclaimed 127\n    [  485.112255] memcg iter ffffff80744e4600 nr_to_reclaim 32 nr_reclaimed 127\n    [  485.115766] memcg iter ffffff8150306e00 nr_to_reclaim 32 nr_reclaimed 191\n    [  485.125635] memcg iter ffffff8157608a00 nr_to_reclaim 32 nr_reclaimed 191\n    [  485.131366] memcg iter ffffff8157754600 nr_to_reclaim 32 nr_reclaimed 216\n    [  485.136688] memcg iter ffffff8157752800 nr_to_reclaim 32 nr_reclaimed 216\n    [  485.140495] memcg iter ffffff8157755000 nr_to_reclaim 32 nr_reclaimed 216\n    [  485.147322] memcg iter ffffff8159461400 nr_to_reclaim 32 nr_reclaimed 216\n    [  485.150605] memcg iter ffffff8159466400 nr_to_reclaim 32 nr_reclaimed 216\n    [  485.158260] memcg iter ffffff8159460a00 nr_to_reclaim 32 nr_reclaimed 216\n    [  485.160819] memcg iter ffffff8159460000 nr_to_reclaim 32 nr_reclaimed 216\n    [  485.163200] memcg iter ffffff8159463c00 nr_to_reclaim 32 nr_reclaimed 216\n    [  485.171778] memcg iter ffffff808912ee00 nr_to_reclaim 32 nr_reclaimed 216\n    [  485.174156] memcg iter ffffff808912a800 nr_to_reclaim 32 nr_reclaimed 216\n    [  485.179110] memcg iter ffffff814bd3a800 nr_to_reclaim 32 nr_reclaimed 216\n    [  485.181537] memcg iter ffffff814bd39e00 nr_to_reclaim 32 nr_reclaimed 216\n    [  485.184877] memcg iter ffffff814bd3da00 nr_to_reclaim 32 nr_reclaimed 219\n    [  485.187245] memcg iter ffffff814bd38a00 nr_to_reclaim 32 nr_reclaimed 219\n    [  485.189654] memcg iter ffffff814bd38000 nr_to_reclaim 32 nr_reclaimed 219\n    [  485.192029] memcg iter ffffff814bd3bc00 nr_to_reclaim 32 nr_reclaimed 219\n    [  485.194509] memcg iter ffffff814bd39400 nr_to_reclaim 32 nr_reclaimed 283\n    [  485.197107] memcg iter ffffff814bd3c600 nr_to_reclaim 32 nr_reclaimed 330\n    [  485.201361] memcg iter ffffff814bd3ee00 nr_to_reclaim 32 nr_reclaimed 394\n    \n    Link: https://lkml.kernel.org/r/20260212032111.408865-1-zhaoyang.huang@unisoc.com\n    Signed-off-by: Zhaoyang Huang <zhaoyang.huang@unisoc.com>\n    Suggested-by: T.J.Mercier <tjmercier@google.com>\n    Reviewed-by: T.J. Mercier <tjmercier@google.com>\n    Cc: Johannes Weiner <hannes@cmpxchg.org>\n    Cc: Michal Hocko <mhocko@kernel.org>\n    Cc: Rik van Riel <riel@surriel.com>\n    Cc: Roman Gushchin <roman.gushchin@linux.dev>\n    Cc: Shakeel Butt <shakeel.butt@linux.dev>\n    Cc: Yu Zhao <yuzhao@google.com>\n    Cc: Axel Rasmussen <axelrasmussen@google.com>\n    Cc: Yuanchu Xie <yuanchu@google.com>\n    Cc: Wei Xu <weixugc@google.com>\n    Signed-off-by: Andrew Morton <akpm@linux-foundation.org>\n\ndiff --git a/mm/vmscan.c b/mm/vmscan.c\nindex e30a11d22086..05a6800f1fa6 100644\n--- a/mm/vmscan.c\n+++ b/mm/vmscan.c\n@@ -4969,10 +4969,6 @@ static bool should_abort_scan(struct lruvec *lruvec, struct scan_control *sc)\n \tint i;\n \tenum zone_watermarks mark;\n \n-\t/* don't abort memcg reclaim to ensure fairness */\n-\tif (!root_reclaim(sc))\n-\t\treturn false;\n-\n \tif (sc->nr_reclaimed >= max(sc->nr_to_reclaim, compact_gap(sc->order)))\n \t\treturn true;\n \n\ncommit dd21e124d7491ad280d9c90e0ac02c705d98e4be\nAuthor: Bing Jiao <bingjiao@google.com>\nDate:   Tue Mar 3 05:25:17 2026 +0000\n\n    mm/vmscan: fix unintended mtc->nmask mutation in alloc_demote_folio()\n    \n    In alloc_demote_folio(), mtc->nmask is set to NULL for the first\n    allocation.  If that succeeds, it returns without restoring mtc->nmask to\n    allowed_mask.  For subsequent allocations from the migrate_pages() batch,\n    mtc->nmask will be NULL.  If the target node then becomes full, the\n    fallback allocation will use nmask = NULL, allocating from any node\n    allowed by the task cpuset, which for kswapd is all nodes.\n    \n    To address this issue, use a local copy of the mtc structure with nmask =\n    NULL for the first allocation attempt specifically, ensuring the original\n    mtc remains unmodified.\n    \n    Link: https://lkml.kernel.org/r/20260303052519.109244-1-bingjiao@google.com\n    Fixes: 320080272892 (\"mm/demotion: demote pages according to allocation fallback order\")\n\n... [Diff truncated. Dropped 32 lines] ...\n\n \t * a demotion of cold pages from the target memtier. This can result\n \t * in the kernel placing hot pages in slower(lower) memory tiers.\n \t */\n-\tmtc->nmask = NULL;\n-\tmtc->gfp_mask |= __GFP_THISNODE;\n-\tdst = alloc_migration_target(src, (unsigned long)mtc);\n+\ttarget_nid_mtc = *mtc;\n+\ttarget_nid_mtc.nmask = NULL;\n+\ttarget_nid_mtc.gfp_mask |= __GFP_THISNODE;\n+\tdst = alloc_migration_target(src, (unsigned long)&target_nid_mtc);\n \tif (dst)\n \t\treturn dst;\n \n-\tmtc->gfp_mask &= ~__GFP_THISNODE;\n-\tmtc->nmask = allowed_mask;\n-\n \treturn alloc_migration_target(src, (unsigned long)mtc);\n }\n \n\ncommit 82879c6d64e4f54400cc37a1efcf62c53216d780\nAuthor: Baolin Wang <baolin.wang@linux.alibaba.com>\nDate:   Fri Mar 6 14:43:41 2026 +0800\n\n    mm: support batched checking of the young flag for MGLRU\n    \n    Use the batched helper test_and_clear_young_ptes_notify() to check and\n    clear the young flag to improve the performance during large folio\n    reclamation when MGLRU is enabled.\n    \n    Meanwhile, we can also support batched checking the young and dirty flag\n    when MGLRU walks the mm's pagetable to update the folios' generation\n    counter.  Since MGLRU also checks the PTE dirty bit, use\n    folio_pte_batch_flags() with FPB_MERGE_YOUNG_DIRTY set to detect batches\n    of PTEs for a large folio.\n    \n    Then we can remove the ptep_test_and_clear_young_notify() since it has no\n    users now.\n    \n    Note that we also update the 'young' counter and 'mm_stats[MM_LEAF_YOUNG]'\n    counter with the batched count in the lru_gen_look_around() and\n    walk_pte_range().  However, the batched operations may inflate these two\n    counters, because in a large folio not all PTEs may have been accessed.\n    (Additionally, tracking how many PTEs have been accessed within a large\n    folio is not very meaningful, since the mm core actually tracks\n    access/dirty on a per-folio basis, not per page).  The impact analysis is\n    as follows:\n    \n    1. The 'mm_stats[MM_LEAF_YOUNG]' counter has no functional impact and\n       is mainly for debugging.\n    \n    2. The 'young' counter is used to decide whether to place the current\n       PMD entry into the bloom filters by suitable_to_scan() (so that next\n       time we can check whether it has been accessed again), which may set\n       the hash bit in the bloom filters for a PMD entry that hasn't seen much\n       access.  However, bloom filters inherently allow some error, so this\n       effect appears negligible.\n    \n    Link: https://lkml.kernel.org/r/378f4acf7d07410aa7c2e4b49d56bb165918eb34.1772778858.git.baolin.wang@linux.alibaba.com\n    Signed-off-by: Baolin Wang <baolin.wang@linux.alibaba.com>\n    Reviewed-by: Rik van Riel <riel@surriel.com>\n    Acked-by: David Hildenbrand (Arm) <david@kernel.org>\n    Cc: Alistair Popple <apopple@nvidia.com>\n    Cc: Axel Rasmussen <axelrasmussen@google.com>\n    Cc: Barry Song <baohua@kernel.org>\n    Cc: Catalin Marinas <catalin.marinas@arm.com>\n    Cc: Dev Jain <dev.jain@arm.com>\n    Cc: Jann Horn <jannh@google.com>\n    Cc: Johannes Weiner <hannes@cmpxchg.org>\n    Cc: Liam Howlett <liam.howlett@oracle.com>\n    Cc: Lorenzo Stoakes <lorenzo.stoakes@oracle.com>\n    Cc: Matthew Wilcox (Oracle) <willy@infradead.org>\n    Cc: Michal Hocko <mhocko@suse.com>\n    Cc: Mike Rapoport <rppt@kernel.org>\n    Cc: Qi Zheng <zhengqi.arch@bytedance.com>\n    Cc: Ryan Roberts <ryan.roberts@arm.com>\n    Cc: Shakeel Butt <shakeel.butt@linux.dev>\n    Cc: Suren Baghdasaryan <surenb@google.com>\n    Cc: Vlastimil Babka <vbabka@suse.cz>\n    Cc: Wei Xu <weixugc@google.com>\n    Cc: Will Deacon <will@kernel.org>\n    Cc: Yuanchu Xie <yuanchu@google.com>\n    Signed-off-by: Andrew Morton <akpm@linux-foundation.org>\n\ndiff --git a/mm/vmscan.c b/mm/vmscan.c\nindex 8f40fff4d0d1..c7fbb6994e73 100644\n--- a/mm/vmscan.c\n+++ b/mm/vmscan.c\n@@ -3478,6 +3478,7 @@ static bool walk_pte_range(pmd_t *pmd, unsigned long start, unsigned long end,\n \tstruct pglist_data *pgdat = lruvec_pgdat(walk->lruvec);\n \tDEFINE_MAX_SEQ(walk->lruvec);\n \tint gen = lru_gen_from_seq(max_seq);\n+\tunsigned int nr;\n \tpmd_t pmdval;\n \n \tpte = pte_offset_map_rw_nolock(args->mm, pmd, start & PMD_MASK, &pmdval, &ptl);\n@@ -3496,11 +3497,13 @@ static bool walk_pte_range(pmd_t *pmd, unsigned long start, unsigned long end,\n \n \tlazy_mmu_mode_enable();\n restart:\n-\tfor (i = pte_index(start), addr = start; addr != end; i++, addr += PAGE_SIZE) {\n+\tfor (i = pte_index(start), addr = start; addr != end; i += nr, addr += nr * PAGE_SIZE) {\n \t\tunsigned long pfn;\n \t\tstruct folio *folio;\n-\t\tpte_t ptent = ptep_get(pte + i);\n+\t\tpte_t *cur_pte = pte + i;\n+\t\tpte_t ptent = ptep_get(cur_pte);\n \n+\t\tnr = 1;\n \t\ttotal++;\n \t\twalk->mm_stats[MM_LEAF_TOTAL]++;\n \n@@ -3512,7 +3515,16 @@ static bool walk_pte_range(pmd_t *pmd, unsigned long start, unsigned long end,\n \t\tif (!folio)\n \t\t\tcontinue;\n \n-\t\tif (!ptep_test_and_clear_young_notify(args->vma, addr, pte + i))\n+\t\tif (folio_test_large(folio)) {\n+\t\t\tconst unsigned int max_nr = (end - addr) >> PAGE_SHIFT;\n+\n+\t\t\tnr = folio_pte_batch_flags(folio, NULL, cur_pte, &ptent,\n+\t\t\t\t\t\t   max_nr, FPB_MERGE_YOUNG_DIRTY);\n+\t\t\ttotal += nr - 1;\n+\t\t\twalk->mm_stats[MM_LEAF_TOTAL] += nr - 1;\n+\t\t}\n+\n+\t\tif (!test_and_clear_young_ptes_notify(args->vma, addr, cur_pte, nr))\n \t\t\tcontinue;\n \n \t\tif (last != folio) {\n@@ -3525,8 +3537,8 @@ static bool walk_pte_range(pmd_t *pmd, unsigned long start, unsigned long end,\n \t\tif (pte_dirty(ptent))\n \t\t\tdirty = true;\n \n-\t\tyoung++;\n-\t\twalk->mm_stats[MM_LEAF_YOUNG]++;\n+\t\tyoung += nr;\n+\t\twalk->mm_stats[MM_LEAF_YOUNG] += nr;\n \t}\n \n \twalk_update_folio(walk, last, gen, dirty);\n@@ -4170,7 +4182,7 @@ static void lru_gen_age_node(struct pglist_data *pgdat, struct scan_control *sc)\n  * the PTE table to the Bloom filter. This forms a feedback loop between the\n  * eviction and the aging.\n  */\n-bool lru_gen_look_around(struct page_vma_mapped_walk *pvmw)\n+bool lru_gen_look_around(struct page_vma_mapped_walk *pvmw, unsigned int nr)\n {\n \tint i;\n \tbool dirty;\n@@ -4193,7 +4205,7 @@ bool lru_gen_look_around(struct page_vma_mapped_walk *pvmw)\n \tlockdep_assert_held(pvmw->ptl);\n \tVM_WARN_ON_ONCE_FOLIO(folio_test_lru(folio), folio);\n \n-\tif (!ptep_test_and_clear_young_notify(vma, addr, pte))\n+\tif (!test_and_clear_young_ptes_notify(vma, addr, pte, nr))\n \t\treturn false;\n \n \tif (spin_is_contended(pvmw->ptl))\n@@ -4233,10 +4245,12 @@ bool lru_gen_look_around(struct page_vma_mapped_walk *pvmw)\n \n \tpte -= (addr - start) / PAGE_SIZE;\n \n-\tfor (i = 0, addr = start; addr != end; i++, addr += PAGE_SIZE) {\n+\tfor (i = 0, addr = start; addr != end;\n+\t     i += nr, pte += nr, addr += nr * PAGE_SIZE) {\n \t\tunsigned long pfn;\n-\t\tpte_t ptent = ptep_get(pte + i);\n+\t\tpte_t ptent = ptep_get(pte);\n \n+\t\tnr = 1;\n \t\tpfn = get_pte_pfn(ptent, vma, addr, pgdat);\n \t\tif (pfn == -1)\n \t\t\tcontinue;\n@@ -4245,7 +4259,14 @@ bool lru_gen_look_around(struct page_vma_mapped_walk *pvmw)\n \t\tif (!folio)\n \t\t\tcontinue;\n \n-\t\tif (!ptep_test_and_clear_young_notify(vma, addr, pte + i))\n+\t\tif (folio_test_large(folio)) {\n+\t\t\tconst unsigned int max_nr = (end - addr) >> PAGE_SHIFT;\n+\n+\t\t\tnr = folio_pte_batch_flags(folio, NULL, pte, &ptent,\n+\t\t\t\t\t\t   max_nr, FPB_MERGE_YOUNG_DIRTY);\n+\t\t}\n+\n+\t\tif (!test_and_clear_young_ptes_notify(vma, addr, pte, nr))\n \t\t\tcontinue;\n \n \t\tif (last != folio) {\n@@ -4258,7 +4279,7 @@ bool lru_gen_look_around(struct page_vma_mapped_walk *pvmw)\n \t\tif (pte_dirty(ptent))\n \t\t\tdirty = true;\n \n-\t\tyoung++;\n+\t\tyoung += nr;\n \t}\n \n \twalk_update_folio(walk, last, gen, dirty);\n\ncommit 2b5340df9b5ab660ea9d33a3dbbd6f564d847d72\nAuthor: Baolin Wang <baolin.wang@linux.alibaba.com>\nDate:   Fri Mar 6 14:43:38 2026 +0800\n\n    mm: rename ptep/pmdp_clear_young_notify() to ptep/pmdp_test_and_clear_young_notify()\n    \n    Rename ptep/pmdp_clear_young_notify() to\n    ptep/pmdp_test_and_clear_young_notify() to make the function names\n    consistent.\n    \n    Link: https://lkml.kernel.org/r/b3454077ce88745e6f88386b1763721746884565.1772778858.git.baolin.wang@linux.alibaba.com\n    Signed-off-by: Baolin Wang <baolin.wang@linux.alibaba.com>\n    Acked-by: David Hildenbrand (Arm) <david@kernel.org>\n    Suggested-by: David Hildenbrand (Arm) <david@kernel.org>\n    Cc: Alistair Popple <apopple@nvidia.com>\n    Cc: Axel Rasmussen <axelrasmussen@google.com>\n    Cc: Barry Song <baohua@kernel.org>\n    Cc: Catalin Marinas <catalin.marinas@arm.com>\n    Cc: Dev Jain <dev.jain@arm.com>\n    Cc: Jann Horn <jannh@google.com>\n    Cc: Johannes Weiner <hannes@cmpxchg.org>\n    Cc: Liam Howlett <liam.howlett@oracle.com>\n    Cc: Lorenzo Stoakes <lorenzo.stoakes@oracle.com>\n    Cc: Matthew Wilcox (Oracle) <willy@infradead.org>\n    Cc: Michal Hocko <mhocko@suse.com>\n    Cc: Mike Rapoport <rppt@kernel.org>\n    Cc: Qi Zheng <zhengqi.arch@bytedance.com>\n    Cc: Rik van Riel <riel@surriel.com>\n    Cc: Ryan Roberts <ryan.roberts@arm.com>\n    Cc: Shakeel Butt <shakeel.butt@linux.dev>\n    Cc: Suren Baghdasaryan <surenb@google.com>\n    Cc: Vlastimil Babka <vbabka@suse.cz>\n    Cc: Wei Xu <weixugc@google.com>\n    Cc: Will Deacon <will@kernel.org>\n    Cc: Yuanchu Xie <yuanchu@google.com>\n    Signed-off-by: Andrew Morton <akpm@linux-foundation.org>\n\ndiff --git a/mm/vmscan.c b/mm/vmscan.c\nindex 363a1c88e1a0..8f40fff4d0d1 100644\n--- a/mm/vmscan.c\n+++ b/mm/vmscan.c\n@@ -3512,7 +3512,7 @@ static bool walk_pte_range(pmd_t *pmd, unsigned long start, unsigned long end,\n \t\tif (!folio)\n \t\t\tcontinue;\n \n-\t\tif (!ptep_clear_young_notify(args->vma, addr, pte + i))\n+\t\tif (!ptep_test_and_clear_young_notify(args->vma, addr, pte + i))\n \t\t\tcontinue;\n \n \t\tif (last != folio) {\n@@ -3603,7 +3603,7 @@ static void walk_pmd_range_locked(pud_t *pud, unsigned long addr, str